hooks.onDraw:
var t = world.t;
var sx = 24, sy = 122, sw = 200, sh = 268;
var cx = sx + sw / 2, cy = sy + sh / 2;
// haz de proyeccion de la IA hacia la pared (sobre las cabezas)
ctx.save();
ctx.globalAlpha = 0.10;
ctx.fillStyle = '#7fb0ff';
ctx.beginPath();
ctx.moveTo(648, 188);
ctx.lineTo(sx + sw, sy + 30);
ctx.lineTo(sx + sw, sy + sh - 30);
ctx.closePath();
ctx.fill();
ctx.restore();
// marco / bisel de la pantalla
ctx.save();
world.draw.rrect(sx - 7, sy - 7, sw + 14, sh + 14, 14);
ctx.fillStyle = '#16131f';
ctx.fill();
world.draw.rrect(sx - 7, sy - 7, sw + 14, sh + 14, 14);
ctx.strokeStyle = 'rgba(120,140,180,0.32)';
ctx.lineWidth = 2;
ctx.stroke();
// superficie
world.draw.rrect(sx, sy, sw, sh, 9);
ctx.fillStyle = '#0c1830';
ctx.fill();
// resplandor frio interno + siluetas (clip a la pantalla)
ctx.save();
world.draw.rrect(sx, sy, sw, sh, 9);
ctx.clip();
var g = ctx.createRadialGradient(cx, cy - 10, 8, cx, cy, sw * 0.95);
g.addColorStop(0, 'rgba(96,156,234,0.46)');
g.addColorStop(0.6, 'rgba(40,82,150,0.22)');
g.addColorStop(1, 'rgba(12,24,48,0)');
ctx.fillStyle = g;
ctx.fillRect(sx, sy, sw, sh);
ctx.fillStyle = 'rgba(7,11,22,0.82)';
// silueta: pajaro a la deriva
var bx = sx + ((t * 20) % (sw + 70)) - 30;
var by = sy + 66 + Math.sin(t * 1.3) * 9;
ctx.save();
ctx.translate(bx, by);
ctx.beginPath();
ctx.moveTo(-16, 0);
ctx.quadraticCurveTo(0, -11, 13, -2);
ctx.quadraticCurveTo(1, 3, -16, 0);
ctx.fill();
ctx.beginPath();
ctx.moveTo(-3, -2);
ctx.quadraticCurveTo(-11, -15, -23, -9 + Math.sin(t * 6) * 4);
ctx.quadraticCurveTo(-9, -5, -3, -2);
ctx.fill();
ctx.restore();
// silueta: figura de pie
var fx = sx + 58 + Math.sin(t * 0.5) * 7;
var fy = sy + sh - 30;
ctx.beginPath();
ctx.arc(fx, fy - 30, 11, 0, Math.PI * 2);
ctx.fill();
ctx.fillRect(fx - 9, fy - 20, 18, 30);
// silueta: arbol
var tx2 = sx + sw - 50;
var ty2 = sy + sh - 14;
ctx.fillRect(tx2 - 4, ty2 - 42, 8, 42);
ctx.beginPath();
ctx.arc(tx2, ty2 - 50, 22, 0, Math.PI * 2);
ctx.fill();
// barrido de escaneo
ctx.globalAlpha = 0.09;
ctx.fillStyle = '#bcd6ff';
var scan = sy + ((t * 38) % sh);
ctx.fillRect(sx, scan, sw, 2);
ctx.globalAlpha = 1;
ctx.restore();
ctx.restore();
// luz fria que la pantalla derrama sobre el publico
var lg = ctx.createRadialGradient(cx + 30, cy + 24, 18, cx + 30, cy + 24, 380);
lg.addColorStop(0, 'rgba(96,156,234,0.15)');
lg.addColorStop(1, 'rgba(96,156,234,0)');
ctx.fillStyle = lg;
ctx.fillRect(0, sy - 50, 660, sh + 140);
// learners (la escena define onDraw, asi que los dibuja ella)
for (var i = 0; i < world.entities.length; i++) {
  var e = world.entities[i];
  if (e.type === 'learner') world.draw.learner(e);
}
